const body = $json.body;
const labels = body.conversation?.labels || [];
const botPaused = labels.includes('humano');
return [{ json: { body, botPaused } }];

const webhookBody = $('Chatwoot Webhook').first().json.body;
const historyData = $input.first().json;

const conversationId = webhookBody.conversation.id;
const currentMessage = webhookBody.content;
const contactName = webhookBody.sender?.name || 'cliente';
const currentSourceId = webhookBody.source_id;

const allMessages = historyData.payload || [];

const incomingOnly = allMessages
  .filter(m => m.content && m.content.trim() && m.message_type === 0);

const sorted = allMessages
  .filter(m => m.content && m.content.trim() && m.message_type !== 2)
  .sort((a, b) => a.created_at - b.created_at)
  .slice(-20);

// Se chegou msg mais nova de cliente após esta, aborta
if (currentSourceId && incomingOnly.length > 0) {
  const lastIncoming = incomingOnly.sort((a, b) => b.created_at - a.created_at)[0];
  if (lastIncoming.source_id && lastIncoming.source_id !== currentSourceId) {
    return [];
  }
}

const messages = [];
for (const m of sorted) {
  const role = m.message_type === 0 ? 'user' : 'model';
  const last = messages[messages.length - 1];
  if (last && last.role === role) {
    last.parts[0].text += '\n' + m.content;
  } else {
    messages.push({ role, parts: [{ text: m.content }] });
  }
}

while (messages.length > 0 && messages[0].role !== 'user') {
  messages.shift();
}

if (messages.length === 0) {
  messages.push({ role: 'user', parts: [{ text: currentMessage }] });
}

return [{ json: { conversationId, contactName, messages } }];

const geminiData = $input.first().json;
const prepared = $('Preparar contexto').first().json;

const fullText = geminiData.candidates?.[0]?.content?.parts?.[0]?.text || '';

const isHandoff = fullText.includes('[HANDOFF]');
const isDemo = fullText.includes('[DEMO]');

const responseText = fullText
  .replace('[HANDOFF]', '')
  .replace('[DEMO]', '')
  .trim();

return [{ json: {
  conversationId: prepared.conversationId,
  responseText,
  isHandoff,
  isDemo
} }];
